import java.io.*;
import java.util.*;

public class Main {
    static int[] parent;
    static int[] size;

    static int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    static void union(int a, int b) {
        int ra = find(a);
        int rb = find(b);
        if (ra == rb) return;
        if (size[ra] < size[rb]) {
            int tmp = ra; ra = rb; rb = tmp;
        }
        parent[rb] = ra;
        size[ra] += size[rb];
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        while (T-- > 0) {
            // read n and m, skipping possible empty lines
            String nmLine;
            do {
                nmLine = br.readLine();
            } while (nmLine != null && nmLine.trim().isEmpty());
            if (nmLine == null) break;
            StringTokenizer st = new StringTokenizer(nmLine);
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            parent = new int[n];
            size = new int[n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                size[i] = 1;
            }
            int processed = 0;
            while (processed < m) {
                String cmdLine = br.readLine();
                if (cmdLine == null) break; // unexpected EOF, stop processing this test case
                cmdLine = cmdLine.trim();
                if (cmdLine.isEmpty()) continue; // skip blank lines
                st = new StringTokenizer(cmdLine);
                String cmd = st.nextToken();
                if (cmd.equals("union")) {
                    int a = Integer.parseInt(st.nextToken());
                    int b = Integer.parseInt(st.nextToken());
                    union(a, b);
                } else { // find
                    int a = Integer.parseInt(st.nextToken());
                    out.append(find(a)).append('\n');
                }
                processed++;
            }
        }
        System.out.print(out.toString());
    }
}

